```typescript
type TypeChaine<T> = T extends string ? T : never;
// Grâce à la distributivité, pour T = string | number | boolean :
// - string extends string ? string : never → string
// - number extends string ? number : never → never
// - boolean extends string ? boolean : never → never
// L'union donne string | never | never → string
```

```typescript
type EstValide<T> = T extends string ? "Chaine OK" :
                    T extends number ? "Nombre OK" :
                    "Type invalide";

// Tests :
// EstValide<string> → "Chaine OK"
// EstValide<number> → "Nombre OK"
// EstValide<boolean> → "Type invalide"
```

```typescript
type TypePort<T> = T extends { port: infer P } ? P : never;

// Test avec l'union Config :
// Pour { env: "dev", port: string } → string
// Pour { env: "prod", port: number, ssl: boolean } → number
// Le résultat de TypePort<Config> est string | number
```
`infer P` capture le type de la propriété `port` quelle que soit la branche de l'union.

```typescript
type GetFieldValue<T> = T extends { value: infer V } ? V : never;

// Résultats :
// GetFieldValue<{ kind: "text", value: string }> → string
// GetFieldValue<{ kind: "number", value: number }> → number
// GetFieldValue<{ kind: "checkbox", value: boolean }> → boolean
```
Cette approche capture automatiquement le type de `value` quel que soit le `kind`.

```typescript
type GetColonneType<T> = T extends { action: "add", typeColonne: infer U }
  ? U extends "string" ? string
  : U extends "number" ? number
  : never
  : never;

// GetColonneType<Migration avec action "add" et typeColonne "string"> → string
// GetColonneType<Migration avec action "add" et typeColonne "number"> → number
// GetColonneType<Migration avec action "remove"> → never
```
